import java.util.Scanner;

public class SafeBufferUsage {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Fixed-size buffer to prevent buffer overflow
        int bufferSize = 10;
        String greeting = "Hello, ";

        if (name.length() <= bufferSize - greeting.length()) {
            String truncatedName = name.substring(0, bufferSize - greeting.length());
            greeting += truncatedName;
        } else {
            System.out.println("Name too long!");
        }

        System.out.println(greeting);

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
